plugins {
	id 'java'
	id 'org.springframework.boot' version '3.3.5'
	id 'io.spring.dependency-management' version '1.1.7'
}

group = 'com.empresa'
version = '0.0.1-SNAPSHOT'
description = 'Auth Service - Spring Boot with JWT and Security'

java {
	toolchain {
		languageVersion = JavaLanguageVersion.of(17)
	}
}

ext {
	set('springCloudVersion', "2023.0.3")
}

repositories {
	mavenCentral()
}

dependencyManagement {
	imports {
		mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudVersion}"
	}
}

dependencies {

	// =========================
	// WEB & VALIDATION
	// =========================
	implementation 'org.springframework.boot:spring-boot-starter-web'
	implementation 'org.springframework.boot:spring-boot-starter-validation'

	// =========================
	// SECURITY & JWT
	// =========================
	implementation 'org.springframework.boot:spring-boot-starter-security'
	implementation 'io.jsonwebtoken:jjwt-api:0.12.3'
	runtimeOnly 'io.jsonwebtoken:jjwt-impl:0.12.3'
	runtimeOnly 'io.jsonwebtoken:jjwt-jackson:0.12.3'

	// =========================
	// MONGODB
	// =========================
	implementation 'org.springframework.boot:spring-boot-starter-data-mongodb'

	// =========================
	// RABBITMQ (EVENTOS)
	// =========================
	implementation 'org.springframework.boot:spring-boot-starter-amqp'

	// =========================
	// OPENAPI (SWAGGER)
	// =========================
	implementation 'org.springdoc:springdoc-openapi-starter-webmvc-ui:2.5.0'

	// =========================
	// MAPSTRUCT
	// =========================
	implementation 'org.mapstruct:mapstruct:1.5.5.Final'
	annotationProcessor 'org.mapstruct:mapstruct-processor:1.5.5.Final'

	// =========================
	// LOMBOK + INTEGRATION
	// =========================
	compileOnly 'org.projectlombok:lombok'
	annotationProcessor 'org.projectlombok:lombok'
	annotationProcessor 'org.projectlombok:lombok-mapstruct-binding:0.2.0'

	// =========================
	// TEST
	// =========================
	testImplementation 'org.springframework.boot:spring-boot-starter-test'
	testImplementation 'org.springframework.security:spring-security-test'
	testImplementation 'de.flapdoodle.embed:de.flapdoodle.embed.mongo:4.10.2'
	testRuntimeOnly 'org.junit.platform:junit-platform-launcher'

	// =========================
	// DEVTOOLS
	// =========================
	developmentOnly 'org.springframework.boot:spring-boot-devtools'
}

tasks.named('test') {
	useJUnitPlatform()
}

package com.empresa.auth_service.config;

import io.swagger.v3.oas.annotations.enums.SecuritySchemeIn;
import io.swagger.v3.oas.annotations.enums.SecuritySchemeType;
import io.swagger.v3.oas.annotations.security.SecurityScheme;
import org.springframework.context.annotation.Configuration;

/**
 * Configuración OpenAPI para exponer el SecurityScheme Bearer en Swagger UI.
 *
 * Permite probar endpoints protegidos desde la interfaz de Swagger añadiendo
 * el token JWT en el header Authorization.
 *
 * @see io.swagger.v3.oas.annotations.security.SecurityScheme
 */
@Configuration
@SecurityScheme(
        name = "bearerAuth",
        type = SecuritySchemeType.HTTP,
        scheme = "bearer",
        bearerFormat = "JWT",
        in = SecuritySchemeIn.HEADER
)
public class OpenApiConfig {

}

package com.empresa.auth_service.config;

import org.springframework.amqp.core.Binding;
import org.springframework.amqp.core.BindingBuilder;
import org.springframework.amqp.core.DirectExchange;
import org.springframework.amqp.core.Queue;
import org.springframework.amqp.rabbit.connection.ConnectionFactory;
import org.springframework.amqp.rabbit.core.RabbitTemplate;
import org.springframework.amqp.rabbit.listener.SimpleRabbitListenerContainerFactory;
import org.springframework.amqp.support.converter.Jackson2JsonMessageConverter;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

/**
 * Configuración de RabbitMQ: queues, exchanges, bindings y conversor JSON.
 *
 * Declara las colas que consume este servicio y los exchanges que usa para
 * publicar eventos. Ajusta nombres mediante properties si se desea.
 *
 * @author Auth Service Team
 * @version 1.0.0
 */
@Configuration
public class RabbitConfig {

    // Queues consumidas por este servicio
    public static final String EMPLEADO_CREADO_QUEUE = "empleado.creado.queue";
    public static final String EMPLEADO_ELIMINADO_QUEUE = "empleado.eliminado.queue";

    // Exchanges para eventos publicados por este servicio
    public static final String USUARIO_CREADO_EXCHANGE = "usuario.creado.exchange";
    public static final String USUARIO_RECUPERACION_EXCHANGE = "usuario.recuperacion.exchange";

    @Bean
    public Queue empleadoCreadoQueue() {
        return new Queue(EMPLEADO_CREADO_QUEUE, true);
    }

    @Bean
    public Queue empleadoEliminadoQueue() {
        return new Queue(EMPLEADO_ELIMINADO_QUEUE, true);
    }

    @Bean
    public DirectExchange usuarioCreadoExchange() {
        return new DirectExchange(USUARIO_CREADO_EXCHANGE);
    }

    @Bean
    public DirectExchange usuarioRecuperacionExchange() {
        return new DirectExchange(USUARIO_RECUPERACION_EXCHANGE);
    }

    // Si necesitas bindings con un exchange de empleados, los puedes declarar aquí.
    // En este ejemplo asumimos que otro servicio publica a exchanges propios.

    @Bean
    public Jackson2JsonMessageConverter jackson2JsonMessageConverter() {
        return new Jackson2JsonMessageConverter();
    }

    @Bean
    public RabbitTemplate rabbitTemplate(ConnectionFactory connectionFactory) {
        RabbitTemplate template = new RabbitTemplate(connectionFactory);
        template.setMessageConverter(jackson2JsonMessageConverter());
        return template;
    }

    @Bean
    public SimpleRabbitListenerContainerFactory rabbitListenerContainerFactory(ConnectionFactory connectionFactory) {
        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
        factory.setConnectionFactory(connectionFactory);
        factory.setMessageConverter(jackson2JsonMessageConverter());
        return factory;
    }
}

package com.empresa.auth_service.security;
import com.empresa.auth_service.domain.entity.User;
import com.empresa.auth_service.exception.InvalidTokenException;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.security.Keys;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import javax.crypto.SecretKey;
import java.util.Date;
import java.util.UUID;
/**
 * Utilidad para generar, validar y parsear tokens JWT.
 * 
 * Esta clase proporciona métodos para:
 * - Generar tokens JWT con información del usuario (email y role)
 * - Verificar si un token es válido
 * - Extraer claims del token (email, role, etc.)
 * - Generar tokens de recuperación cortos
 * 
 * La clave secreta se inyecta desde la variable de entorno JWT_SECRET.
 * Usa el algoritmo HS512 para firmar los tokens.
 * 
 * @author Auth Service Team
 * @version 1.0.0
 */
@Slf4j
@Component
public class JwtUtils {
    /**
     * Clave secreta para firmar los tokens (inyectada desde propiedades)
     */
    @Value("${jwt.secret:${JWT_SECRET:MiClaveSecretaSuperLargaYSeguraParaFirmarTokensJWTPorFavor123456789}}")
    private String jwtSecret;
    /**
     * Tiempo de expiración del token en milisegundos (24 horas)
     */
    @Value("${jwt.expiration:86400000}")
    private long jwtExpirationMs;
    /**
     * Tiempo de expiración del token de recuperación en milisegundos (24 horas)
     */
    @Value("${jwt.recovery.expiration:86400000}")
    private long recoveryTokenExpirationMs;
    /**
     * Genera un token JWT para un usuario autenticado.
     * 
     * Claims incluidos:
     * - sub (subject): email del usuario
     * - role: rol del usuario
     * 
     * @param user el usuario para el que se genera el token
     * @return el token JWT generado
     */
    public String generateToken(User user) {
        log.debug("Generando token JWT para usuario: {}", user.getEmail());
        Date now = new Date();
        Date expiryDate = new Date(now.getTime() + jwtExpirationMs);
        SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes());
        return Jwts.builder()
                .subject(user.getEmail())
                .claim("role", user.getRole().getAuthority())
                .issuedAt(now)
                .expiration(expiryDate)
                .signWith(key, SignatureAlgorithm.HS512)
                .compact();
    }
    /**
     * Genera un token de recuperación de contraseña (UUID simple).
     * 
     * Este token se almacena en la BD y es diferente al JWT.
     * Es un UUID simple que sirve como identificador temporal.
     * 
     * @return un token de recuperación único
     */
    public String generateRecoveryToken() {
        return UUID.randomUUID().toString();
    }
    /**
     * Obtiene el email (subject) de un token JWT.
     * 
     * @param token el token JWT
     * @return el email del usuario
     * @throws InvalidTokenException si el token es inválido
     */
    public String getEmailFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return claims.getSubject();
        } catch (Exception e) {
            log.error("Error extrayendo email del token", e);
            throw new InvalidTokenException("No se pudo extraer el email del token", e);
        }
    }
    /**
     * Obtiene el rol de un token JWT.
     * 
     * @param token el token JWT
     * @return el rol del usuario
     * @throws InvalidTokenException si el token es inválido
     */
    public String getRoleFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return (String) claims.get("role");
        } catch (Exception e) {
            log.error("Error extrayendo role del token", e);
            throw new InvalidTokenException("No se pudo extraer el role del token", e);
        }
    }
    /**
     * Obtiene la fecha de expiración de un token JWT.
     * 
     * @param token el token JWT
     * @return la fecha de expiración
     * @throws InvalidTokenException si el token es inválido
     */
    public Date getExpirationDateFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return claims.getExpiration();
        } catch (Exception e) {
            log.error("Error extrayendo fecha de expiración del token", e);
            throw new InvalidTokenException("No se pudo extraer la fecha de expiración", e);
        }
    }
    /**
     * Verifica si un token JWT es válido (no expirado y bien formado).
     * 
     * @param token el token JWT a validar
     * @return true si el token es válido, false en caso contrario
     */
    public boolean validateToken(String token) {
        try {
            getAllClaimsFromToken(token);
            return !isTokenExpired(token);
        } catch (Exception e) {
            log.error("Error validando token de seguridad", e);
            return false;
        }
    }
    /**
     * Extrae todos los claims (información) de un token JWT.
     * 
     * @param token el token JWT
     * @return los claims del token
     * @throws InvalidTokenException si el token es inválido
     */
    private Claims getAllClaimsFromToken(String token) {
        try {
            SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes());
            return Jwts.parser()
                    .verifyWith(key)
                    .build()
                    .parseSignedClaims(token)
                    .getPayload();
        } catch (Exception e) {
            log.error("Error parseando token JWT: {}", e.getMessage());
            throw new InvalidTokenException("Token JWT inválido: " + e.getMessage(), e);
        }
    }
    /**
     * Verifica si un token ha expirado.
     * 
     * @param token el token JWT
     * @return true si ha expirado, false en caso contrario
     */
    private boolean isTokenExpired(String token) {
        try {
            Date expiration = getExpirationDateFromToken(token);
            return expiration.before(new Date());
        } catch (Exception e) {
            log.error("Error verificando expiración del token", e);
            return true;
        }
    }
}

package com.empresa.auth_service.security;
import com.empresa.auth_service.domain.entity.User;
import com.empresa.auth_service.exception.InvalidTokenException;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.security.Keys;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import javax.crypto.SecretKey;
import java.util.Date;
import java.util.UUID;
/**
 * Utilidad para generar, validar y parsear tokens JWT.
 * 
 * Esta clase proporciona métodos para:
 * - Generar tokens JWT con información del usuario (email y role)
 * - Verificar si un token es válido
 * - Extraer claims del token (email, role, etc.)
 * - Generar tokens de recuperación cortos
 * 
 * La clave secreta se inyecta desde la variable de entorno JWT_SECRET.
 * Usa el algoritmo HS512 para firmar los tokens.
 * 
 * @author Auth Service Team
 * @version 1.0.0
 */
@Slf4j
@Component
public class JwtUtils {
    /**
     * Clave secreta para firmar los tokens (inyectada desde propiedades)
     */
    @Value("${jwt.secret:${JWT_SECRET:MiClaveSecretaSuperLargaYSeguraParaFirmarTokensJWTPorFavor123456789}}")
    private String jwtSecret;
    /**
     * Tiempo de expiración del token en milisegundos (24 horas)
     */
    @Value("${jwt.expiration:86400000}")
    private long jwtExpirationMs;
    /**
     * Tiempo de expiración del token de recuperación en milisegundos (24 horas)
     */
    @Value("${jwt.recovery.expiration:86400000}")
    private long recoveryTokenExpirationMs;
    /**
     * Genera un token JWT para un usuario autenticado.
     * 
     * Claims incluidos:
     * - sub (subject): email del usuario
     * - role: rol del usuario
     * 
     * @param user el usuario para el que se genera el token
     * @return el token JWT generado
     */
    public String generateToken(User user) {
        log.debug("Generando token JWT para usuario: {}", user.getEmail());
        Date now = new Date();
        Date expiryDate = new Date(now.getTime() + jwtExpirationMs);
        SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes());
        return Jwts.builder()
                .subject(user.getEmail())
                .claim("role", user.getRole().getAuthority())
                .issuedAt(now)
                .expiration(expiryDate)
                .signWith(key, SignatureAlgorithm.HS512)
                .compact();
    }
    /**
     * Genera un token de recuperación de contraseña (UUID simple).
     * 
     * Este token se almacena en la BD y es diferente al JWT.
     * Es un UUID simple que sirve como identificador temporal.
     * 
     * @return un token de recuperación único
     */
    public String generateRecoveryToken() {
        return UUID.randomUUID().toString();
    }
    /**
     * Obtiene el email (subject) de un token JWT.
     * 
     * @param token el token JWT
     * @return el email del usuario
     * @throws InvalidTokenException si el token es inválido
     */
    public String getEmailFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return claims.getSubject();
        } catch (Exception e) {
            log.error("Error extrayendo email del token", e);
            throw new InvalidTokenException("No se pudo extraer el email del token", e);
        }
    }
    /**
     * Obtiene el rol de un token JWT.
     * 
     * @param token el token JWT
     * @return el rol del usuario
     * @throws InvalidTokenException si el token es inválido
     */
    public String getRoleFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return (String) claims.get("role");
        } catch (Exception e) {
            log.error("Error extrayendo role del token", e);
            throw new InvalidTokenException("No se pudo extraer el role del token", e);
        }
    }
    /**
     * Obtiene la fecha de expiración de un token JWT.
     * 
     * @param token el token JWT
     * @return la fecha de expiración
     * @throws InvalidTokenException si el token es inválido
     */
    public Date getExpirationDateFromToken(String token) {
        try {
            Claims claims = getAllClaimsFromToken(token);
            return claims.getExpiration();
        } catch (Exception e) {
            log.error("Error extrayendo fecha de expiración del token", e);
            throw new InvalidTokenException("No se pudo extraer la fecha de expiración", e);
        }
    }
    /**
     * Verifica si un token JWT es válido (no expirado y bien formado).
     * 
     * @param token el token JWT a validar
     * @return true si el token es válido, false en caso contrario
     */
    public boolean validateToken(String token) {
        try {
            getAllClaimsFromToken(token);
            return !isTokenExpired(token);
        } catch (Exception e) {
            log.error("Error validando token de seguridad", e);
            return false;
        }
    }
    /**
     * Extrae todos los claims (información) de un token JWT.
     * 
     * @param token el token JWT
     * @return los claims del token
     * @throws InvalidTokenException si el token es inválido
     */
    private Claims getAllClaimsFromToken(String token) {
        try {
            SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes());

            // Uso compatible con jjwt 0.12.x
            return Jwts.parserBuilder()
                    .setSigningKey(key)
                    .build()
                    .parseClaimsJws(token)
                    .getBody();
        } catch (Exception e) {
            log.error("Error parseando token JWT: {}", e.getMessage());
            throw new InvalidTokenException("Token JWT inválido: " + e.getMessage(), e);
        }
    }
    /**
     * Verifica si un token ha expirado.
     * 
     * @param token el token JWT
     * @return true si ha expirado, false en caso contrario
     */
    private boolean isTokenExpired(String token) {
        try {
            Date expiration = getExpirationDateFromToken(token);
            return expiration.before(new Date());
        } catch (Exception e) {
            log.error("Error verificando expiración del token", e);
            return true;
        }
    }
}

package com.empresa.auth_service.service;
import com.empresa.auth_service.domain.entity.User;
import com.empresa.auth_service.domain.enums.Role;
import com.empresa.auth_service.dto.request.LoginRequest;
import com.empresa.auth_service.dto.response.LoginResponse;
import com.empresa.auth_service.exception.AuthException;
import com.empresa.auth_service.exception.UserNotFoundException;
import com.empresa.auth_service.repository.UserRepository;
import com.empresa.auth_service.security.JwtUtils;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.rabbit.core.RabbitTemplate;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import java.time.LocalDateTime;
/**
 * Servicio de autenticación y autorización.
 * 
 * Proporciona métodos para:
 * - Loguear usuarios y generar tokens JWT
 * - Recuperar contraseña (enviar evento)
 * - Resetear contraseña con token
 * - Crear usuarios (para eventos)
 * 
 * @author Auth Service Team
 * @version 1.0.0
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class AuthService {
    /**
     * Repositorio de usuarios
     */
    private final UserRepository userRepository;
    /**
     * Utilidad para generar y validar JWT
     */
    private final JwtUtils jwtUtils;
    /**
     * Encoder de contraseñas
     */
    private final PasswordEncoder passwordEncoder;
    /**
     * Template de RabbitMQ para publicar eventos
     */
    private final RabbitTemplate rabbitTemplate;
    /**
     * Autentica un usuario y genera un token JWT.
     * 
     * Proceso:
     * 1. Busca el usuario por email
     * 2. Verifica la contraseña
     * 3. Verifica que el usuario esté habilitado
     * 4. Genera un token JWT
     * 5. Retorna la respuesta con el token
     * 
     * @param loginRequest credenciales del usuario
     * @return LoginResponse con el token JWT
     * @throws UserNotFoundException si el usuario no existe
     * @throws AuthException si las credenciales son inválidas
     */
    public LoginResponse login(LoginRequest loginRequest) {
        log.info("Intento de login para usuario: {}", loginRequest.getEmail());
        User user = userRepository.findByEmail(loginRequest.getEmail())
                .orElseThrow(() -> {
                    log.warn("Usuario no encontrado: {}", loginRequest.getEmail());
                    return new UserNotFoundException("Usuario no encontrado: " + loginRequest.getEmail());
                });
        // Verificar que el usuario está habilitado
        if (!user.getEnabled()) {
            log.warn("Intento de login con usuario deshabilitado: {}", loginRequest.getEmail());
            throw new AuthException("Usuario deshabilitado");
        }
        // Validar contraseña
        if (!passwordEncoder.matches(loginRequest.getPassword(), user.getPassword())) {
            log.warn("Contraseña incorrecta para usuario: {}", loginRequest.getEmail());
            throw new AuthException("Credenciales inválidas");
        }
        log.info("Login exitoso para usuario: {}", loginRequest.getEmail());
        // Generar token JWT
        String token = jwtUtils.generateToken(user);
        long expiresIn = 86400; // 24 horas en segundos
        return LoginResponse.builder()
                .accessToken(token)
                .tokenType("Bearer")
                .email(user.getEmail())
                .role(user.getRole().getAuthority())
                .expiresIn(expiresIn)
                .build();
    }
    /**
     * Inicia el proceso de recuperación de contraseña.
     * 
     * Proceso:
     * 1. Busca el usuario por email
     * 2. Genera un token de recuperación UUID
     * 3. Guarda el token en la BD
     * 4. Publica evento "usuario.recuperacion" en RabbitMQ
     * 
     * @param email el email del usuario
     * @throws UserNotFoundException si el usuario no existe
     */
    public void recoverPassword(String email) {
        log.info("Solicitud de recuperación de contraseña para: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> {
                    log.warn("Usuario no encontrado para recuperación: {}", email);
                    return new UserNotFoundException("Usuario no encontrado: " + email);
                });
        // Generar token de recuperación
        String recoveryToken = jwtUtils.generateRecoveryToken();
        user.setRecoveryToken(recoveryToken);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.debug("Token de recuperación generado para: {}", email);
        // Publicar evento en RabbitMQ
        publishPasswordRecoveryEvent(email, recoveryToken);
    }
    /**
     * Resetea la contraseña del usuario usando el token de recuperación.
     * 
     * Proceso:
     * 1. Busca el usuario por token de recuperación
     * 2. Valida que el token sea válido
     * 3. Encripta la nueva contraseña
     * 4. Guarda la nueva contraseña
     * 5. Limpia el token de recuperación
     * 
     * @param recoveryToken el token de recuperación
     * @param newPassword la nueva contraseña
     * @throws AuthException si el token es inválido o expirado
     */
    public void resetPassword(String recoveryToken, String newPassword) {
        log.info("Solicitud de reseteo de contraseña con token: {}", recoveryToken);
        User user = userRepository.findByRecoveryToken(recoveryToken)
                .orElseThrow(() -> {
                    log.warn("Token de recuperación inválido: {}", recoveryToken);
                    return new AuthException("Token de recuperación inválido o expirado");
                });
        // Encriptar la nueva contraseña
        String hashedPassword = passwordEncoder.encode(newPassword);
        user.setPassword(hashedPassword);
        user.setRecoveryToken(null);  // Limpiar el token
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Contraseña actualizada para usuario: {}", user.getEmail());
    }
    /**
     * Crea un nuevo usuario desde un evento (ej: empleado.creado).
     * 
     * El usuario se crea inhabilitado, esperando que el usuario
     * complete el proceso de recuperación de contraseña.
     * 
     * @param email el email del usuario
     * @param role el rol asignado
     * @return User creado
     */
    public User createUser(String email, Role role) {
        log.info("Creando nuevo usuario: {} con rol: {}", email, role);
        // Verificar que el usuario no exista
        if (userRepository.existsByEmail(email)) {
            log.warn("Usuario ya existe: {}", email);
            throw new AuthException("El usuario ya existe: " + email);
        }
        User user = User.builder()
                .email(email)
                .password("")  // Sin contraseña inicial
                .role(role)
                .enabled(false)  // Usuario inhabilitado hasta que recupere contraseña
                .build();
        User savedUser = userRepository.save(user);
        log.info("Usuario creado existosamente: {}", email);
        return savedUser;
    }
    /**
     * Habilita un usuario después de que establece su contraseña.
     * 
     * @param email el email del usuario
     * @param password la contraseña inicial
     */
    public void enableUser(String email, String password) {
        log.info("Habilitando usuario: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new UserNotFoundException("Usuario no encontrado: " + email));
        user.setPassword(passwordEncoder.encode(password));
        user.setEnabled(true);
        user.setRecoveryToken(null);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Usuario habilitado: {}", email);
    }
    /**
     * Inhabilita un usuario.
     * 
     * @param email el email del usuario
     */
    public void disableUser(String email) {
        log.info("Deshabilitando usuario: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new UserNotFoundException("Usuario no encontrado: " + email));
        user.setEnabled(false);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Usuario deshabilitado: {}", email);
    }
    /**
     * Publica evento de recuperación de contraseña en RabbitMQ.
     * 
     * El evento incluye el email y el token de recuperación.
     * Los interesados pueden usar este evento para enviar email, SMS, etc.
     * 
     * @param email el email del usuario
     * @param recoveryToken el token de recuperación
     */
    private void publishPasswordRecoveryEvent(String email, String recoveryToken) {
        try {
            PasswordRecoveryEvent event = new PasswordRecoveryEvent(email, recoveryToken);
            rabbitTemplate.convertAndSend("usuario.recuperacion.exchange", "usuario.recuperacion.key", event);
            log.debug("Evento de recuperación publicado para: {}", email);
        } catch (Exception e) {
            log.error("Error publicando evento de recuperación", e);
            // No lanzar excepción - el usuario fue creado correctamente
        }
    }
    /**
     * DTO interno para el evento de recuperación de contraseña
     */
    public static class PasswordRecoveryEvent {
        public String email;
        public String recoveryToken;
        public PasswordRecoveryEvent(String email, String recoveryToken) {
            this.email = email;
            this.recoveryToken = recoveryToken;
        }
    }
}

package com.empresa.auth_service.service;
import com.empresa.auth_service.domain.entity.User;
import com.empresa.auth_service.domain.enums.Role;
import com.empresa.auth_service.dto.request.LoginRequest;
import com.empresa.auth_service.dto.response.LoginResponse;
import com.empresa.auth_service.exception.AuthException;
import com.empresa.auth_service.exception.UserNotFoundException;
import com.empresa.auth_service.repository.UserRepository;
import com.empresa.auth_service.security.JwtUtils;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.rabbit.core.RabbitTemplate;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import java.time.LocalDateTime;
/**
 * Servicio de autenticación y autorización.
 * 
 * Proporciona métodos para:
 * - Loguear usuarios y generar tokens JWT
 * - Recuperar contraseña (enviar evento)
 * - Resetear contraseña con token
 * - Crear usuarios (para eventos)
 * 
 * @author Auth Service Team
 * @version 1.0.0
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class AuthService {
    /**
     * Repositorio de usuarios
     */
    private final UserRepository userRepository;
    /**
     * Utilidad para generar y validar JWT
     */
    private final JwtUtils jwtUtils;
    /**
     * Encoder de contraseñas
     */
    private final PasswordEncoder passwordEncoder;
    /**
     * Template de RabbitMQ para publicar eventos
     */
    private final RabbitTemplate rabbitTemplate;
    /**
     * Autentica un usuario y genera un token JWT.
     * 
     * Proceso:
     * 1. Busca el usuario por email
     * 2. Verifica la contraseña
     * 3. Verifica que el usuario esté habilitado
     * 4. Genera un token JWT
     * 5. Retorna la respuesta con el token
     * 
     * @param loginRequest credenciales del usuario
     * @return LoginResponse con el token JWT
     * @throws UserNotFoundException si el usuario no existe
     * @throws AuthException si las credenciales son inválidas
     */
    public LoginResponse login(LoginRequest loginRequest) {
        log.info("Intento de login para usuario: {}", loginRequest.getEmail());
        User user = userRepository.findByEmail(loginRequest.getEmail())
                .orElseThrow(() -> {
                    log.warn("Usuario no encontrado: {}", loginRequest.getEmail());
                    return new UserNotFoundException("Usuario no encontrado: " + loginRequest.getEmail());
                });
        // Verificar que el usuario está habilitado
        if (!user.getEnabled()) {
            log.warn("Intento de login con usuario deshabilitado: {}", loginRequest.getEmail());
            throw new AuthException("Usuario deshabilitado");
        }
        // Validar contraseña
        if (!passwordEncoder.matches(loginRequest.getPassword(), user.getPassword())) {
            log.warn("Contraseña incorrecta para usuario: {}", loginRequest.getEmail());
            throw new AuthException("Credenciales inválidas");
        }
        log.info("Login exitoso para usuario: {}", loginRequest.getEmail());
        // Generar token JWT
        String token = jwtUtils.generateToken(user);
        long expiresIn = 86400; // 24 horas en segundos
        return LoginResponse.builder()
                .accessToken(token)
                .tokenType("Bearer")
                .email(user.getEmail())
                .role(user.getRole().getAuthority())
                .expiresIn(expiresIn)
                .build();
    }
    /**
     * Inicia el proceso de recuperación de contraseña.
     * 
     * Proceso:
     * 1. Busca el usuario por email
     * 2. Genera un token de recuperación UUID
     * 3. Guarda el token en la BD
     * 4. Publica evento "usuario.recuperacion" en RabbitMQ
     * 
     * @param email el email del usuario
     * @throws UserNotFoundException si el usuario no existe
     */
    public void recoverPassword(String email) {
        log.info("Solicitud de recuperación de contraseña para: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> {
                    log.warn("Usuario no encontrado para recuperación: {}", email);
                    return new UserNotFoundException("Usuario no encontrado: " + email);
                });
        // Generar token de recuperación
        String recoveryToken = jwtUtils.generateRecoveryToken();
        user.setRecoveryToken(recoveryToken);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.debug("Token de recuperación generado para: {}", email);
        // Publicar evento en RabbitMQ
        publishPasswordRecoveryEvent(email, recoveryToken);
    }
    /**
     * Resetea la contraseña del usuario usando el token de recuperación.
     * 
     * Proceso:
     * 1. Busca el usuario por token de recuperación
     * 2. Valida que el token sea válido
     * 3. Encripta la nueva contraseña
     * 4. Guarda la nueva contraseña
     * 5. Limpia el token de recuperación
     * 
     * @param recoveryToken el token de recuperación
     * @param newPassword la nueva contraseña
     * @throws AuthException si el token es inválido o expirado
     */
    public void resetPassword(String recoveryToken, String newPassword) {
        log.info("Solicitud de reseteo de contraseña con token: {}", recoveryToken);
        User user = userRepository.findByRecoveryToken(recoveryToken)
                .orElseThrow(() -> {
                    log.warn("Token de recuperación inválido: {}", recoveryToken);
                    return new AuthException("Token de recuperación inválido o expirado");
                });
        // Encriptar la nueva contraseña
        String hashedPassword = passwordEncoder.encode(newPassword);
        user.setPassword(hashedPassword);
        user.setRecoveryToken(null);  // Limpiar el token
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Contraseña actualizada para usuario: {}", user.getEmail());
    }
    /**
     * Crea un nuevo usuario desde un evento (ej: empleado.creado).
     * 
     * El usuario se crea inhabilitado, esperando que el usuario
     * complete el proceso de recuperación de contraseña.
     * 
     * @param email el email del usuario
     * @param role el rol asignado
     * @return User creado
     */
    public User createUser(String email, Role role) {
        log.info("Creando nuevo usuario: {} con rol: {}", email, role);
        // Verificar que el usuario no exista
        if (userRepository.existsByEmail(email)) {
            log.warn("Usuario ya existe: {}", email);
            throw new AuthException("El usuario ya existe: " + email);
        }
        User user = User.builder()
                .email(email)
                .password("")  // Sin contraseña inicial
                .role(role)
                .enabled(false)  // Usuario inhabilitado hasta que recupere contraseña
                .build();
        User savedUser = userRepository.save(user);
        log.info("Usuario creado existosamente: {}", email);
        return savedUser;
    }
    /**
     * Habilita un usuario después de que establece su contraseña.
     * 
     * @param email el email del usuario
     * @param password la contraseña inicial
     */
    public void enableUser(String email, String password) {
        log.info("Habilitando usuario: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new UserNotFoundException("Usuario no encontrado: " + email));
        user.setPassword(passwordEncoder.encode(password));
        user.setEnabled(true);
        user.setRecoveryToken(null);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Usuario habilitado: {}", email);
    }
    /**
     * Inhabilita un usuario.
     * 
     * @param email el email del usuario
     */
    public void disableUser(String email) {
        log.info("Deshabilitando usuario: {}", email);
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new UserNotFoundException("Usuario no encontrado: " + email));
        user.setEnabled(false);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
        log.info("Usuario deshabilitado: {}", email);
    }

    /**
     * Genera un token de recuperación (delegando a JwtUtils).
     *
     * @return token de recuperación
     */
    public String generateRecoveryToken() {
        return jwtUtils.generateRecoveryToken();
    }

    /**
     * Guarda el token de recuperación para el usuario identificado por email.
     *
     * @param email usuario al que se asigna el token
     * @param token token de recuperación
     */
    public void saveRecoveryToken(String email, String token) {
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new UserNotFoundException("Usuario no encontrado: " + email));

        user.setRecoveryToken(token);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);
    }

    /**
     * Elimina un usuario por su email.
     *
     * @param email email del usuario a eliminar
     */
    public void deleteUser(String email) {
        userRepository.findByEmail(email).ifPresent(userRepository::delete);
    }
    /**
     * Publica evento de recuperación de contraseña en RabbitMQ.
     * 
     * El evento incluye el email y el token de recuperación.
     * Los interesados pueden usar este evento para enviar email, SMS, etc.
     * 
     * @param email el email del usuario
     * @param recoveryToken el token de recuperación
     */
    private void publishPasswordRecoveryEvent(String email, String recoveryToken) {
        try {
            PasswordRecoveryEvent event = new PasswordRecoveryEvent(email, recoveryToken);
            rabbitTemplate.convertAndSend("usuario.recuperacion.exchange", "usuario.recuperacion.key", event);
            log.debug("Evento de recuperación publicado para: {}", email);
        } catch (Exception e) {
            log.error("Error publicando evento de recuperación", e);
            // No lanzar excepción - el usuario fue creado correctamente
        }
    }
    /**
     * DTO interno para el evento de recuperación de contraseña
     */
    public static class PasswordRecoveryEvent {
        public String email;
        public String recoveryToken;
        public PasswordRecoveryEvent(String email, String recoveryToken) {
            this.email = email;
            this.recoveryToken = recoveryToken;
        }
    }
}

## JWT
jwt.secret=${JWT_SECRET:ChangeThisSecretToARealOneWithAtLeast256bits}
jwt.expiration=86400000

## MongoDB
spring.data.mongodb.uri=${MONGO_URI:mongodb://localhost:27017/auth_db}

## RabbitMQ
spring.rabbitmq.host=${RABBITMQ_HOST:localhost}
spring.rabbitmq.port=${RABBITMQ_PORT:5672}
spring.rabbitmq.username=${RABBITMQ_USERNAME:guest}
spring.rabbitmq.password=${RABBITMQ_PASSWORD:guest}

## Rabbit queues/exchanges names (optional override)
app.rabbit.empleado.creado.queue=empleado.creado.queue
app.rabbit.empleado.eliminado.queue=empleado.eliminado.queue
app.rabbit.usuario.creado.exchange=usuario.creado.exchange
app.rabbit.usuario.recuperacion.exchange=usuario.recuperacion.exchange

# Spring boot server port (optional)
server.port=8090
